command:
mkdir -p bd/u1
printf '{"iac_file":"main.tf","tool":"terraform"}' > bd/u1/unit.json
cat > bd/u1/main.tf <<'JEOF'
terraform { required_version = ">= 1.5" required_providers { aws = { source = "hashicorp/aws" } } }
variable "name" { description = "n" type = string }
resource "aws_s3_bucket" "b" { tags = { env = "prod" } }
JEOF
bash "$CLAUDE_PLUGIN_ROOT/commands/cloud-conventions.sh" --unit u1 --build-dir bd
